  List<int> offsets,
  Map<Type, List<int>> allOffsets,
) {
  writer.writeString(offsets[0], object.currency_ID);
  writer.writeString(offsets[1], object.englishName);
  writer.writeString(offsets[2], object.food_category_ID);
  writer.writeString(offsets[3], object.id);
  writer.writeString(offsets[4], object.isActive);
  writer.writeString(offsets[5], object.isDelivery);
  writer.writeBool(offsets[6], object.isDirty);
  writer.writeString(offsets[7], object.isRecommend);
  writer.writeString(offsets[8], object.isServeTable);
  writer.writeString(offsets[9], object.isTakeAway);
  writer.writeString(offsets[10], object.kitchenName);
  writer.writeString(offsets[11], object.lastUpdated);
  writer.writeString(offsets[12], object.localPicture);
  writer.writeString(offsets[13], object.picture);
  writer.writeDouble(offsets[14], object.price);
  writer.writeLong(offsets[15], object.seq);
  writer.writeString(offsets[16], object.thaiName);
}

